        subtitle: "Basic worker initialization and message passing",
        signature: "new Worker(scriptURL, options?) → Worker instance",
        descLong: "Web Workers run JavaScript in separate threads. Use new Worker() with a script URL, or create inline workers with Blob and URL.createObjectURL(). Communicate via postMessage() for structured clone data transfer.",
        examples: [
                  {
                            "tier": "intro",
                            "code": "// === ENTRY-LEVEL EXAMPLE ===\n// TASK      - Basic usage of new Worker(path) / URL.createObjectURL() — understand the core syntax and behavior.\n// APPROACH  - Simple example with minimal parameters; no edge cases.\n// STRENGTHS - Clear, readable; shows the fundamental pattern.\n// WEAKNESSES- Not production-ready; no error handling or complex scenarios.\n// APPROACH  - the simplest Web Worker: create, send data, receive result.\n// STRENGTHS - three lines; shows postMessage + onmessage lifecycle.\n// WEAKNESSES- no error handling, no termination, no transferables.\n//\n// GOAL: offload CPU work to a background thread\n// WHY: workers keep the UI responsive; they have no DOM/window access\nconst worker = new Worker('compute.js');\nworker.postMessage({ data: [1, 2, 3] });\nworker.onmessage = (e) => console.log(e.data.result);"
                  },
                  {
                            "tier": "junior",
                            "code": "// === JUNIOR EXAMPLE ===\n// TASK      - Real-world usage of new Worker(path) / URL.createObjectURL() — common patterns you'll see in production.\n// APPROACH  - Combine new Worker(path) / URL.createObjectURL() with related functions; handle common edge cases.\n// STRENGTHS - Practical; covers the 80% use cases encountered on the job.\n// WEAKNESSES- May need optimization for large datasets or complex queries.\n// APPROACH  - error handling, inline worker with Blob, worker-side logic\n// STRENGTHS - shows inline worker creation and error handling\n// WEAKNESSES- no transferables, no termination, no promise wrapper\n//\n// GOAL: new Worker(path) / URL.createObjectURL()\n// WHY: Create and communicate with Web Workers\n// Main thread\nconst worker = new Worker('compute.js');\nworker.postMessage({ data: [1, 2, 3, 4, 5] });\nworker.onmessage = (event) => {\n  console.log('Result:', event.data.result);\n};\nworker.onerror = (error) => console.error(error.message);\n// Inline worker with Blob\nconst blob = new Blob([`\n  self.onmessage = (e) => self.postMessage(e.data * 2);\n`], { type: 'application/javascript' });\nconst inlineWorker = new Worker(URL.createObjectURL(blob));\ninlineWorker.postMessage(21);\n// Worker thread (compute.js)\nself.onmessage = (event) => {\n  const sum = event.data.data.reduce((a, b) => a + b, 0);\n  self.postMessage({ result: sum });\n};"
                  },
                  {
                            "tier": "senior",
                            "code": "// === SENIOR EXAMPLE ===\n// TASK      - Advanced usage of new Worker(path) / URL.createObjectURL() — performance, edge cases, and expert patterns.\n// APPROACH  - Production-grade patterns; optimization; handling complex scenarios.\n// STRENGTHS - Complete; handles edge cases, performance, and maintainability.\n// WEAKNESSES- Complex; requires deep knowledge to understand and maintain.\n// APPROACH  - a promise-based worker wrapper with request/response correlation\n//             via message IDs, inline worker creation, and automatic cleanup.\n// STRENGTHS - one reusable class eliminates callback hell; request/response\n//             correlation supports concurrent tasks; terminate() frees resources.\n// WEAKNESSES- class boilerplate; overkill for a single fire-and-forget task.\n//\n// GOAL: production worker wrapper with promise-based RPC and cleanup\n// WHY: raw postMessage is callback-based; no request/response correlation; workers leak if not terminated\nclass WorkerClient {\n  #worker = null;\n  #pending = new Map();\n  #nextId = 0;\n  constructor(scriptUrlOrCode, options = {}) {\n    if (typeof scriptUrlOrCode === 'string') {\n      this.#worker = new Worker(scriptUrlOrCode, options);\n    } else {\n      // Inline worker from code string\n      const blob = new Blob([scriptUrlOrCode], { type: 'application/javascript' });\n      this.#worker = new Worker(URL.createObjectURL(blob), options);\n    }\n    this.#worker.onmessage = (e) => {\n      const { id, result, error } = e.data;\n      const cb = this.#pending.get(id);\n      if (!cb) return;\n      this.#pending.delete(id);\n      error ? cb.reject(new Error(error)) : cb.resolve(result);\n    };\n    this.#worker.onerror = (e) => {\n      // Reject all pending on fatal error\n      for (const [, cb] of this.#pending) cb.reject(new Error(e.message));\n      this.#pending.clear();\n    };\n  }\n  exec(task, transferables = []) {\n    return new Promise((resolve, reject) => {\n      const id = this.#nextId++;\n      this.#pending.set(id, { resolve, reject });\n      this.#worker.postMessage({ id, task }, transferables);\n    });\n  }\n  terminate() {\n    this.#worker.terminate();\n    this.#pending.clear();\n  }\n}\n// Usage: external worker\nconst client = new WorkerClient('compute.js');\nconst result = await client.exec({ type: 'sum', data: [1, 2, 3] });\nconsole.log('Sum:', result);\nclient.terminate();\n// Usage: inline worker\nconst inline = new WorkerClient([\n  'self.onmessage = (e) => {',\n  '  const { id, task } = e.data;',\n  '  if (task.type === \"fib\") {',\n  '    const fib = (n) => n <= 1 ? n : fib(n - 1) + fib(n - 2);',\n  '    self.postMessage({ id, result: fib(task.n) });',\n  '  }',\n  '};',\n].join('\\n'));\nconst fib40 = await inline.exec({ type: 'fib', n: 40 });\nconsole.log('Fib(40):', fib40);\ninline.terminate();\n// Worker thread (compute.js) — must echo { id, result } back\n// self.onmessage = (e) => {\n//   const { id, task } = e.data;\n//   if (task.type === 'sum') {\n//     self.postMessage({ id, result: task.data.reduce((a, b) => a + b, 0) });\n//   }\n// };\n// Decision rule:\n//   external script                          -> new Worker('file.js')\n//   dynamic/inline code                      -> Blob + URL.createObjectURL()\n//   dependencies inside worker               -> importScripts() (classic) or import (module)\n//   concurrent tasks on one worker           -> correlate via message IDs (above)\n//   done with worker                         -> worker.terminate() to free resources\n//\n// Anti-pattern: touching the DOM inside a worker; leaking workers by never\n//   terminating; using onmessage callback for request/response without IDs\n//   (responses arrive out of order with concurrent tasks)."
                  }
        ],
